/**
 * 全型定義一覧データ
 * ✅=初期設定 →=継承(前フェーズから流れてくる) ✏️=更新(既存値を変更) 🔧=未実装 ⛔=不可 —=無関係
 *
 * field命名規則（型定義上の正式プロパティパスに統一）:
 *   - セクションA/E/F: DocEntryトップレベルプロパティ名をそのまま使用
 *   - セクションB: DocEntryの ai* プレフィックス付きプロパティ名（例: aiDate, aiAmount）
 *   - セクションC(配列): lineItems[], lineItemsCount
 *   - セクションC(内部): `li.xxx`（LineItem内部フィールド。セクションB・Iと同名フィールドの区別用）
 *   - セクションD: `aiMetrics.xxx`（DocEntry.aiMetrics の子プロパティ）
 *   - セクションG: `job.xxx`（MigrationJob型。DocEntry外の独立エンティティ）
 *   - セクションH: マスタ型名をそのまま使用（Staff, Client等）
 *   - セクションI〜O: `journal.xxx`（JournalPhase5Mock型のプロパティ）
 */

export type CellValue = '✅' | '→' | '✏️' | '🔧' | '⛔' | '—'

export interface TypeField {
  field: string; label: string; tsType: string
  // 1. アップロード独自
  uploadOwnAi: CellValue; uploadOwnTs: CellValue; uploadOwnHuman: CellValue
  // 2. アップロードDrive
  uploadDriveAi: CellValue; uploadDriveTs: CellValue; uploadDriveHuman: CellValue
  // 3. 選別独自
  selectOwnAi: CellValue; selectOwnTs: CellValue; selectOwnHuman: CellValue
  // 4. 選別Drive
  selectDriveAi: CellValue; selectDriveTs: CellValue; selectDriveHuman: CellValue
  // 5. 仕訳変換
  convertAi: CellValue; convertTs: CellValue; convertHuman: CellValue
  // 6. 科目確定
  accountAi: CellValue; accountTs: CellValue; accountHuman: CellValue
  // 7. 仕訳一覧
  journalAi: CellValue; journalTs: CellValue; journalHuman: CellValue
  // 8. 出力
  outMf: CellValue; outCost: CellValue; outStaffCount: CellValue; outStaffTime: CellValue
  // 9. ダッシュB（管理者ダッシュボード）
  dashB: CellValue
  // 10. 学習（顧問先別学習ルール）
  learning: CellValue
  dataSource: string
  note: string
}

export interface TypeSection { title: string; icon: string; fields: TypeField[] }

